    """Truncate `s` to at most `n` grapheme clusters. Never split a cluster."""
    if n <= 0:
        return ''
    clusters = []
    current_cluster = []
    i = 0
    while i < len(s) and len(clusters) < n:
        c = s[i]
        # Rule 1: Base character starts a new cluster
        if not current_cluster or unicodedata.category(c) not in ('M', 'Zs'):
            if current_cluster:
                clusters.append(''.join(current_cluster))
            current_cluster = [c]
        else:
            # Rule 2: Combining mark extends current cluster
            current_cluster.append(c)
        # Rule 3: ZWJ joins next character into the same cluster
        if c == '\u200d':
            if i + 1 < len(s):
                current_cluster.append(s[i + 1])
                i += 1
        # Rule 4: Regional indicators pair if next is RI
        if unicodedata.category(c) == 'Lo' and c >= '\U0001F1E6' and c <= '\U0001F1FF':
            if i + 1 < len(s) and unicodedata.category(s[i + 1]) == 'Lo' and s[i + 1] >= '\U0001F1E6' and s[i + 1] <= '\U0001F1FF':
                current_cluster.append(s[i + 1])
                i += 1
        # Rule 5: Variation selector extends current cluster
        if unicodedata.category(c) == 'Cf' and c >= '\U000FE00' and c <= '\U000FE0F':
            current_cluster.append(c)
        i += 1
    if current_cluster:
        clusters.append(''.join(current_cluster))
    return ''.join(clusters[:n])

